# Category: insecure_crypto

import hashlib

def file_hash(filepath, algorithm='sha256'):
    """Generate a hash of a file's contents."""
    hasher = hashlib.new(algorithm)
    with open(filepath, 'rb') as f:
        while chunk := f.read(4096):
            hasher.update(chunk)
    return hasher.hexdigest()

